import { calculateItemPrice } from "../calculateItemPrice";

describe("calculateItemPrice", () => {
  it("debe calcular el total del item por cantidad", () => {
    expect(calculateItemPrice(15000, 3)).toBe(45000);
  });

  it("debe retornar cero si la cantidad es cero", () => {
    expect(calculateItemPrice(15000, 0)).toBe(0);
  });

  it("debe lanzar error si la cantidad es negativa", () => {
    expect(() => calculateItemPrice(15000, -1)).toThrow(
      "La cantidad no puede ser negativa"
    );
  });
});
